INSERT INTO `sys_oper_log` VALUES (484, '代码生成', 8, 'com.ruoyi.generator.controller.GenController.batchGenCode()', 'GET', 1, 'admin', '/tool/gen/batchGenCode', '127.0.0.1', '内网IP', '{\"tables\":\"sys_medicineremind\"}', NULL, 0, NULL, '2024-04-05 19:00:37', 353);
INSERT INTO `sys_oper_log` VALUES (485, '药品资讯信息', 2, 'com.ruoyi.web.controller.system.SysArticleController.edit()', 'PUT', 1, 'admin', '/system/article', '127.0.0.1', '内网IP', '{\"author\":\"刘琼\",\"homePage\":\"https://yztx-application.oss-cn-guangzhou.aliyuncs.com/cd4e9697-7000-4c4c-80fa-8aa974c13fb3.jpg\",\"id\":1,\"imageText\":\"<p><strong>家庭常用药品储存，您做对了吗？</strong></p><p><br></p><p><span style=\\\"color: rgb(0, 0, 0);\\\">近日，有位阿姨带来了一瓶泰嘉片，咨询是否还能继续服用。经过仔细检查后发现，药片已不同程度地泛黄，有些甚至出现了开裂，还发现瓶中药片数量远远超过了原包装的数量。原来阿姨每次配药回去，都会把多瓶药片拆开，装在一个瓶子里。阿姨的这个习惯大大增加了药品受潮的机会，致使药品变质。</span></p><p class=\\\"ql-align-justify\\\">现代家庭中大多储备了一些基本药物，如何正确的保存药品，保证药品的稳定性、有效性，防止药物变质、降低疗效。以下就简单介绍一下药品储存需注意的问题。</p><p class=\\\"ql-align-justify\\\">01</p><p class=\\\"ql-align-justify\\\">药品储存四要素</p><p class=\\\"ql-align-justify\\\">绝大多数药品都很容易受到环境因素的影响而发生物理、化学变化。引起这些变化的常见原因包括光线、湿气和热度等。因此，药品保存的首要原则就是密封、避光、避湿、避热。</p><p class=\\\"ql-align-justify\\\">1）密闭保存。在服用完药品后应该尽快密封盖严，以免空气中的氧气等与药品反应而引起药品变质。如鱼肝油氧化变红、维生素C发生氧化而变黄，氨茶碱易吸收二氧化碳而成茶碱。</p><p class=\\\"ql-align-justify\\\">2）注意避光。大部分西药是化学制剂，阳光中紫外线的照射可以加速药品的变质，特别是维生素类药物，见光后会变色，导致药效降低，甚至变成有毒的物质。因此，储存药品时要注意避光。</p><p class=\\\"ql-align-justify\\\">3）注意防潮。有些药物极易吸收空气中的水分，从而水解使药品失效。如酵母片、复方甘草片、维生素B片、颠茄片以及各种胶囊和糖衣片遇湿容易变性；阿斯匹林、淀粉酶、胰酶等片剂吸潮易变质。存放这类药物时要注意防潮，最好放在家中阴凉干燥的地方。没有特殊说明的药品不要存放于冰箱，拿出来服用忘了放回去，更容易受潮。</p><p><img src=\\\"https://yztx-application.oss-cn-guangzhou.aliyuncs.com/bcd9f2f5-8550-45f3-bee4-93f02792013d.jpg\\\"></p><p class=\\\"ql-align-justify\\\">4）注意温度。药物的化学反应随温度的上升而加快。药品应放在家中最阴凉处，避免变质。冷藏药品则需放置于冰箱中，并保持在 2℃~10℃之间，如胰岛素制剂、部分微生态制剂等。注意栓剂如果温度过高 (如超过40℃) 则可能会出现软化、融化或变形的情况，影响药物的使用，一般应放置于阴凉处或冰箱中冷藏。</p><p class=\\\"ql-align-justify\\\">02</p><p class=\\\"ql-align-justify\\\">药品分开存放更安全</p><p class=\\\"ql-align-justify\\\">各种药品混放在一起不但容易导致相互污染影响药品质量，还容易发生因拿错药而误服的现象。建议大家存放药品时合理分类摆放，中药和西药分开，外用药和内服药分开，避免服错，避免串味。</p><p class=\\\"ql-align-justify\\\">03</p><p class=\\\"ql-align-justify\\\">药品标签要完整清晰</p><p class=\\\"ql-align-justify\\\">尽量保留药品原包装，保证药品标签完整、清晰，如果药物不是原装的，一定要把药物的名称、用途、用法、用量、注意事项和有效期等详细标明。</p><p class=\\\"ql-align-justify\\\">04</p><p class=\\\"ql-align-justify\\\">定期检查除隐患</p><p><img src=\\\"https://yztx-application.oss-cn-guangzhou.aliyuncs.com/4673a361-17a4-4a3f-91b4-11b26ddd3a57.jpg\\\"></p><p class=\\\"ql-align-justify\\\">建议每3—6个月清理', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-04-05 19:06:43', 26);
INSERT INTO `sys_oper_log` VALUES (486, '代码生成', 8, 'com.ruoyi.generator.controller.GenController.batchGenCode()', 'GET', 1, 'admin', '/tool/gen/batchGenCode', '127.0.0.1', '内网IP', '{\"tables\":\"sys_medicineremind\"}', NULL, 0, NULL, '2024-04-05 19:14:26', 187);
