"superColumn\":false,\"tableId\":15,\"updateBy\":\"\",\"usableColumn\":false},{\"capJavaField\":\"HomePage\",\"columnComment\":\"封面图片\",\"columnId\":129,\"columnName\":\"home_page\",\"columnType\":\"varchar(255)\",\"createBy\":\"admin\",\"createTime\":\"2024-04-06 00:41:55\",\"dictType\":\"\",\"edit\":true,\"htmlType\":\"input\",\"increment\":false,\"insert\":true,\"isEdit\":\"1\",\"isIncrement\":\"0\",\"isInsert\":\"1\",\"isList\":\"1\",\"isPk\":\"0\",\"isQuery\":\"1\",\"javaField\":\"homePage\",\"javaType\":\"String\",\"list\":tru', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-04-06 00:42:15', 42);
