INSERT INTO `sys_rehb_video` VALUES (1, '1', '创伤的急救与自救', '<video class=\"ql-video\" controls=\"controls\" src=\"https://yztx-application.oss-cn-guangzhou.aliyuncs.com/84c0259a-e5b5-4247-9277-0d66ecd983bf.mp4\" controlslist=\"nodownload noremoteplayback\" type=\"video/mp4\" style=\"object-fit:fill;width: 100%;\" preload=\"auto\" playsinline=\"true\" x-webkit-airplay=\"allow\" x5-video-orientation=\"portraint\" x5-playsinline=\"true\" x5-video-player-fullscreen=\"true\"></video><p><br></p>', 1421, '创伤的急救与自救原则包括：  一、快速脱离危险环境，避免进一步的损伤；  二、保持伤员安静，避免不必要的搬动；  三、对于怀疑有颈椎骨折的病人，要注意颈椎的保护，避免颈椎过度扭动，造成肢体截瘫；', 'https://yztx-application.oss-cn-guangzhou.aliyuncs.com/0eee9128-3b5d-4a2a-8ccb-0e0ad6d2bad4.jpg');
INSERT INTO `sys_rehb_video` VALUES (2, '1', '车祸外伤的急救处理', '<video class=\"ql-video\" controls=\"controls\" src=\"https://yztx-application.oss-cn-guangzhou.aliyuncs.com/b6c635c9-b2ec-48b3-98bc-887727c2e826.mp4\" controlslist=\"nodownload noremoteplayback\" type=\"video/mp4\" style=\"object-fit:fill;width: 100%;\" preload=\"auto\" playsinline=\"true\" x-webkit-airplay=\"allow\" x5-video-orientation=\"portraint\" x5-playsinline=\"true\" x5-video-player-fullscreen=\"true\"></video><p><br></p>', 1201, '车祸外伤以后，首先，要评估患者的状态，有没有意识丧失。如果患者意识还行，监测患者的生命体征、血压、心率、呼吸、脉搏等。', 'https://yztx-application.oss-cn-guangzhou.aliyuncs.com/3ae92e06-88c9-4be8-9dc5-7dfb424d0e41.jpg');
INSERT INTO `sys_rehb_video` VALUES (3, '1', '成人心肺复苏的办法', '<video class=\"ql-video\" controls=\"controls\" src=\"https://yztx-application.oss-cn-guangzhou.aliyuncs.com/2db0aa90-b010-48e4-bf11-5cbe44de3505.mp4\" controlslist=\"nodownload noremoteplayback\" type=\"video/mp4\" style=\"object-fit:fill;width: 100%;\" preload=\"auto\" playsinline=\"true\" x-webkit-airplay=\"allow\" x5-video-orientation=\"portraint\" x5-playsinline=\"true\" x5-video-player-fullscreen=\"true\"></video><p><br></p>', 1245, '成年人心跳骤停时，现场目击者首先要胸外心脏按压30次，按压要快速、有力，按压深度5-6cm，按压频率100-120次/分(30次按压耗时15-18秒)。头偏向一侧，徒手清理口鼻分泌物、呕吐物等异物，取出活动假体，用仰头举颏法打开气道。', 'https://yztx-application.oss-cn-guangzhou.aliyuncs.com/2acb05fc-0666-4458-b1ed-0ec2b9f38438.jpg');
INSERT INTO `sys_rehb_video` VALUES (4, '2', '昏迷的急救方法', '<video class=\"ql-video\" controls=\"controls\" src=\"https://yztx-application.oss-cn-guangzhou.aliyuncs.com/dc1e8800-ae0d-4149-a439-79d0cbda5010.mp4\" controlslist=\"nodownload noremoteplayback\" type=\"video/mp4\" style=\"object-fit:fill;width: 100%;\" preload=\"auto\" playsinline=\"true\" x-webkit-airplay=\"allow\" x5-video-orientation=\"portraint\" x5-playsinline=\"true\" x5-video-player-fullscreen=\"true\"></video><p><br></p>', 1122, '发现有病人昏迷的时候，首先，要确定病人是不是真的昏迷了，可以拍打患者的双肩，在患者的双耳大声喊叫，观察患者的反应。如果真的昏迷，要立即拨打120急救电话，如果旁边有其他人，还要喊其他人帮忙。', 'https://yztx-application.oss-cn-guangzhou.aliyuncs.com/1a16e2d4-4860-4322-9fce-938024c2740e.jpg');
INSERT INTO `sys_rehb_video` VALUES (5, '2', '电击伤的急救如何处理', '<video class=\"ql-video\" controls=\"controls\" src=\"https://yztx-application.oss-cn-guangzhou.aliyuncs.com/25f6427c-062f-4aa5-95c6-838e0204ab34.mp4\" controlslist=\"nodownload noremoteplayback\" type=\"video/mp4\" style=\"object-fit:fill;width: 100%;\" preload=\"auto\" playsinline=\"true\" x-webkit-airplay=\"allow\" x5-video-orientation=\"portraint\" x5-playsinline=\"true\" x5-video-player-fullscreen=\"true\"></video><p><br></p>', 1024, '生活中电击伤非常常见，被高压电击伤以后，容易出现皮肤、肌肉组织的损伤，最严重的是可以导致心律失常、心脏骤停。如果没有及时抢救，可能会出现患者死亡的情况。', 'https://yztx-application.oss-cn-guangzhou.aliyuncs.com/18ffb785-ba74-45c0-b3c9-ee994ae3913e.jpg');
INSERT INTO `sys_rehb_video` VALUES (6, '2', '头被重拍一下的急救方法', '<video class=\"ql-video\" controls=\"controls\" src=\"https://yztx-application.oss-cn-guangzhou.aliyuncs.com/210d42e4-5e71-4220-991a-05847b910b59.mp4\" controlslist=\"nodownload noremoteplayback\" type=\"video/mp4\" style=\"object-fit:fill;width: 100%;\" preload=\"auto\" playsinline=\"true\" x-webkit-airplay=\"allow\" x5-video-orientation=\"portraint\" x5-playsinline=\"true\" x5-video-player-fullscreen=\"true\"></video><p><br></p>', 1265, '头被重重的拍一下，一般包括下面几种情况：一、受伤以后只是出现头晕不适，这种情况先让患者休息一会，看看有什么症状，然后再送医院去做颅脑CT检查。  二、被拍了一下以后患者立即出现昏迷、恶心、呕吐，说明有颅骨或者颅内的出血，这种情况比较严重，需要将患者置于侧卧位，避免误吸，然后抓紧时间送医院去做颅脑CT检查，观察颅内的情况。', 'https://yztx-application.oss-cn-guangzhou.aliyuncs.com/2bfd2a6b-a3c6-4306-9791-8f530f3c42b6.jpg');
INSERT INTO `sys_rehb_video` VALUES (7, '2', '食物中毒的急救措施', '<video class=\"ql-video\" controls=\"controls\" src=\"https://yztx-application.oss-cn-guangzhou.aliyuncs.com/c070b6a2-72a7-4791-825b-80a848fc0bff.mp4\" controlslist=\"nodownload noremoteplayback\" type=\"video/mp4\" style=\"object-fit:fill;width: 100%;\" preload=\"auto\" playsinline=\"true\" x-webkit-airplay=\"allow\" x5-video-orientation=\"portraint\" x5-playsinline=\"true\" x5-video-player-fullscreen=\"true\"></video><p><br></p>', 1658, '当患者存在危及生命的临床表现时，首先应该立即给予处置，包括保护患者的气道，维持呼吸、循环功能稳定等，以保护重要脏器的血流灌注，然后再给予相应的对因及对症治疗。对于意识清醒的食物中毒患者，结合其食物中毒的产生原因，评估病情及预后，可以选择催吐、洗胃、导泻等治疗，以减少毒素的再吸收，加速排泄。同时，可视病情的需要，必要的情况下给予特异性的解毒药物使用，以及进行血液净化治疗等，以减轻已吸收毒素的损伤，并促使其排出体外。', 'https://yztx-application.oss-cn-guangzhou.aliyuncs.com/2dd49e1f-b971-4424-8d49-1202f36e140b.jpg');
INSERT INTO `sys_rehb_video` VALUES (8, '2', '误食亚硝酸盐后如何急救', '<video class=\"ql-video\" controls=\"controls\" src=\"https://yztx-application.oss-cn-guangzhou.aliyuncs.com/0ebe789f-4c18-45d3-a5c1-53618c279732.mp4\" controlslist=\"nodownload noremoteplayback\" type=\"video/mp4\" style=\"object-fit:fill;width: 100%;\" preload=\"auto\" playsinline=\"true\" x-webkit-airplay=\"allow\" x5-video-orientation=\"portraint\" x5-playsinline=\"true\" x5-video-player-fullscreen=\"true\"></video><p><br></p>', 1146, '亚硝酸盐中毒主要引起高铁血红蛋白血症，氧无法和血红蛋白结合运输到组织器官，造成机体组织器官缺氧。中毒时要立即给病人吸氧、监测生命体征、建立静脉通路。如果病人血压下降，给予多巴胺和间羟胺等药物升压；如果病人出现呼吸衰竭，在吸氧的同时应用呼吸兴奋剂尼可刹米等，必要时气管插管呼吸机辅助通气；同时要立即洗胃，用活性炭吸附、硫酸镁导泻等方法促进毒物的排出。', 'https://yztx-application.oss-cn-guangzhou.aliyuncs.com/eba50aed-35d7-4afd-9007-0d190a1856ca.jpg');
INSERT INTO `sys_rehb_video` VALUES (9, '1', '食物窒息的急救措施', '<video class=\"ql-video\" controls=\"controls\" src=\"https://yztx-application.oss-cn-guangzhou.aliyuncs.com/372646f5-daf3-433f-81fb-fb8b9dc063a5.mp4\" controlslist=\"nodownload noremoteplayback\" type=\"video/mp4\" style=\"object-fit:fill;width: 100%;\" preload=\"auto\" playsinline=\"true\" x-webkit-airplay=\"allow\" x5-video-orientation=\"portraint\" x5-playsinline=\"true\" x5-video-player-fullscreen=\"true\"></video><p><br></p>', 1231, '出现食物窒息的急救，现在国际上公认最有效的方法是海姆立克急救法。即给患者中上腹部一个向内向上的冲击力，然后使膈肌迅速上抬，从而缩窄整个胸腔，使气道有一个向上的冲击力，可以促使阻塞在气道里面的食物排出口腔。', 'https://yztx-application.oss-cn-guangzhou.aliyuncs.com/97560380-8992-463e-8125-fcc2a856baea.jpg');
INSERT INTO `sys_rehb_video` VALUES (10, '1', '急性心梗的急救护理', '<video class=\"ql-video\" controls=\"controls\" src=\"https://yztx-application.oss-cn-guangzhou.aliyuncs.com/e846c3e6-edf2-46f5-b17c-d935216a4e1b.mp4\" controlslist=\"nodownload noremoteplayback\" type=\"video/mp4\" style=\"object-fit:fill;width: 100%;\" preload=\"auto\" playsinline=\"true\" x-webkit-airplay=\"allow\" x5-video-orientation=\"portraint\" x5-playsinline=\"true\" x5-video-player-fullscreen=\"true\"></video><p><br></p>', 1565, '急性心肌梗死是因为冠脉血管病变造成局部心肌细胞缺血、缺氧而心肌坏死。主要治疗是冠脉介入对病变血管，也就是责任血管植入支架或者进行溶栓，尽快再通血管，减少心肌坏死的数量，缩小梗死的范围，尽可能保护心脏的功能。', 'https://yztx-application.oss-cn-guangzhou.aliyuncs.com/26471712-8987-4a66-80fd-703557db31d7.jpg');
